// Sadece 'koptu' olayinda kurtarma (recovery) calistir:
// 1) Postgres konteyneri durmussa baslat  2) Servis A uygulama blogunu temizle
const event = $('DB Baglanti Webhook').first().json.body.event || '';
if (event === 'koptu') {
  const { execSync } = require('child_process');
  try { execSync('docker start tasarim_proje-postgres-1', { timeout: 15000 }); } catch (e) {}
  try { execSync('wget -qO- --timeout=5 http://servis_a:5000/db/reconnect', { timeout: 8000 }); } catch (e) {}
}
return $input.all();
